/* ── Google Apps Script API (JSONP) ──────────── */
async function gasPost(action, data={}) {
  const params = "data=" + encodeURIComponent(JSON.stringify({action, secret: SECRET, ...data}));
  try {
    const r = await fetch(GAS_URL + "?" + params);
    return await r.json();
  } catch(e) {
    try {
      await fetch(GAS_URL + "?" + params, {mode:"no-cors"});
    } catch(e2) {}
    return {ok: true};
  }
}

async function gasGet(action) {
  try {
    const r = await fetch(GAS_URL + "?action=" + action);
    return await r.json();
  } catch(e) {
    return {ok: true, data: {}};
  }
}

function gasJsonp(params) {
  return new Promise((resolve, reject) => {
    const cbName = "cb_" + Math.random().toString(36).slice(2);
    const script = document.createElement("script");
    const timeout = setTimeout(() => {
      cleanup();
      reject(new Error("Timeout"));
    }, 3000);
    function cleanup() {
      clearTimeout(timeout);
      delete window[cbName];
      if (script.parentNode) script.parentNode.removeChild(script);
    }
    window[cbName] = (data) => { cleanup(); resolve(data); };
    script.src = GAS_URL + "?" + params + "&callback=" + cbName;
    script.onerror = () => { cleanup(); reject(new Error("Script error")); };
    document.head.appendChild(script);
  });
}

// Auth
const sendOTP = (email) => gasPost("sendOTP", {email});
const verifyOTP = (email, otp) => gasPost("verifyOTP", {email, otp});
const saveUserName = (email, name) => gasPost("saveName", {email, name});
const getUserByEmail = (email) => gasPost("getUserByEmail", {email}).then(r => r.name||"");

// Predictions
const getPreds = (name) => gasPost("getPredictions", {name}).then(r => r.data||[]);
const upsertPred = (name, matchId, hg, ag) => gasPost("savePrediction", {name, matchId, hg, ag});
const deletePred = (name, matchId) => gasPost("deletePrediction", {name, matchId});

// News & Comments
const getNews = () => gasGet("getNews").then(r=>r.data||[]);
const getComments = (news_id) => gasPost("getComments", {news_id}).then(r=>r.data||[]);
const addComment = (news_id, name, comment) => gasPost("addComment", {news_id, name, comment});

// Like post
const likePost = (news_id, name) => gasPost("likePost", {news_id, name});
// Edit/Delete comment
const editComment = (comment_id, name, comment) => gasPost("editComment", {comment_id, name, comment});
const deleteComment = (comment_id, name) => gasPost("deleteComment", {comment_id, name});

// Delete user
const deleteUser = (email, name) => gasPost("deleteUser", {email, name});

// Scores & Leaderboard
const getScores = () => gasGet("getScores").then(r => r.data||{});
const getLB = () => gasGet("getLeaderboard").then(r => r.data||[]);
const saveScoreDB = (matchId, hg, ag, status="") => gasPost("saveScore", {matchId, hg, ag, status});


